const projectReducer = (state = initialState, action) => {
    switch (action.type) {
        case FILTER_PROJECT: {
            const { id } = action.payload;
            return state.filter(project => project.id === id)[0] || null
        }
        default:
            return state
    }
}

export default projectReducer