import React from 'react'
import { Link, withRouter } from 'react-router-dom'

const Navbar = ({ history }) => {
    const handleNav = (e) => {
        const target = e.target.dataset.target
        if (!document.querySelector(target)) {
            history.push(`/${target}`)
        }
    }

    return (
        <nav className="navbar navbar-expand-lg navbar-light py-2 py-sm-3">
            <div className="container">
                <div className="w-100 row no-gutters px-2 justify-content-between">
                    <span className="navbar-brand mb-0 h1 px-2">
                        <Link to="/">
                            <img src="https://res.cloudinary.com/ds-projects/image/upload/dysetiawan/Logo.png" alt="Dicky Setiawan" height={24} />
                        </Link>
                    </span>
                    <button className="navbar-toggler border-0 px-1" type="button" data-toggle="collapse" data-target="#navbar" aria-controls="navbar" aria-expanded="false" aria-label="Toggle navigation">
                        <span className="navbar-toggler-icon" />
                    </button>
                    <div className="collapse navbar-collapse justify-content-end" id="navbar">
                        <ul className="navbar-nav my-3 my-lg-0">
                            <li className="nav-item">
                                <button className="nav-link" type="button" onClick={handleNav} data-target="#about" title="About me">About</button>
                            </li>
                            <li className="nav-item">
                                <button className="nav-link" type="button" onClick={handleNav} data-target="#services" title="My services">Services</button>
                            </li>
                            <li className="nav-item">
                                <button className="nav-link" type="button" onClick={handleNav} data-target="#skills" title="My skills">Skills</button>
                            </li>
                            <li className="nav-item">
                                <button className="nav-link" type="button" onClick={handleNav} data-target="#works" title="My works">Works</button>
                            </li>
                            <li className="nav-item">
                                <button className="nav-link" type="button" onClick={handleNav} data-target="#contact" title="Contact me">Contact</button>
                            </li>
                        </ul>
                    </div>
                </div>
            </div>
        </nav>
    )
}
export default withRouter(Navbar)