import React from 'react'
import { Link, withRouter } from 'react-router-dom'
import { Helmet } from 'react-helmet'
import LazyLoad from 'react-lazyload'
import ProjectList from './ProjectList'
import PageNotFound from '../fallback/PageNotFound'
import { connect } from 'react-redux'

const ProjectDetails = (props) => {
    const { project, latest, history } = props

    const stretchedLink = (e) => {
        const id = e.target.dataset.id
        if (id) {
            history.push(`/project/${id}`)
        }
    }

    return project ? (
        <article>
            <Helmet>
                <title>{project.title} | Dicky Setiawan</title>
                <meta name="description" content={project.tagline} />
                <body id="project-detail"></body>
            </Helmet>
            <div className="container">
                <div className="row justify-content-center">
                    <div className="col-12 col-sm-10 col-md-9 col-xl-8">
                        <div className="article-header">
                            <div className="project-link">
                                <Link to="/" className="back-to-home">
                                    <span className="material-icons">
                                        chevron_left
                                    </span>
                                    Back To Home
                                </Link>
                                {project.demo && (
                                    <a className="visit-site" href={project.demo} target="_blank" rel="nofollow noopener noreferrer">
                                        <span className="material-icons">
                                            open_in_new
                                        </span>
                                        Visit Site
                                    </a>
                                )}
                            </div>
                            <div className="project-title">{project.name}</div>
                            <div className="project-tagline">{project.tagline}</div>
                        </div>
                        <div className="article-content">
                            <figure>
                                <LazyLoad throttle={750} placeholder={(<img className="project-image img-fluid" src="https://res.cloudinary.com/ds-projects/image/upload/dysetiawan/image.png" alt={project.title} />)}>
                                    <img className="project-image img-fluid" src={project.image} alt={project.title} />
                                </LazyLoad>
                                <figcaption>{project.title}</figcaption>
                            </figure>
                            {project.about && (
                                <div className="section">
                                    <div className="section-title">About this project</div>
                                    <div className="section-content">
                                        <p>{project.about}</p>
                                    </div>
                                </div>
                            )}
                            {project.techs && (
                            <div className="section">
                                <div className="section-title">Technical Sheet</div>
                                <div className="section-content">
                                    <ul>
                                        {project.techs.map((tech, id) => (
                                            <li key={id}>{tech}</li>
                                        ))}
                                    </ul>
                                </div>
                            </div>
                            )}
                        </div>
                        <div className="article-suggestion">
                            <div className="row">
                                <div className="col">
                                    <div className="title">
                                        Latest Projects
                                    </div>
                                </div>
                            </div>
                            <div className="row row-cols-1 row-cols-md-2">
                                <ProjectList projects={latest} stretchedLink={stretchedLink} />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </article>
    ) : (<PageNotFound />)
}

const mapStateToProps = (state, ownProps) => {
    const { projects } = state
    const id = ownProps.match.params.id

    const filtered = projects.filter(project => project.id === id)
    const unfiltered = projects.filter(project => project.id !== id)
    const latest = unfiltered.slice(Math.max(unfiltered.length - 2, 0))

    return { project: filtered[0] || null, latest }
}

export default connect(mapStateToProps)(withRouter(ProjectDetails))