import React from 'react'
import LazyLoad from 'react-lazyload'
import { connect } from 'react-redux'
import { Link } from 'react-router-dom'

const Projects = ({ projects, stretchedLink }) => {
    const projectList = projects.length ? (
        projects.map(project => (
            <div key={project.id} className="col project-wrapper">
                <div className="image-wrapper" onClick={stretchedLink} data-id={project.id}>
                    <LazyLoad throttle={750} placeholder={(<img className="project-image img-fluid" src="https://res.cloudinary.com/ds-projects/image/upload/dysetiawan/image.png" alt={project.title} />)}>
                        <img className="project-image img-fluid" src={project.image} alt={project.title} />
                    </LazyLoad>
                </div>
                <div className="link-wrapper">
                    <Link to={`/project/${project.id}`}>
                        <span className="material-icons">code</span>
                        {project.title}
                    </Link>
                    {project.demo && (
                        <a href={project.demo} target="_blank" rel="nofollow noopener noreferrer">
                            <span className="material-icons">open_in_new</span>
                        Visit Site
                        </a>
                    )}
                </div>
            </div>
        ))
    ) : (<div className="col"></div>)

    return (
        <section id="works">
            <div className="container">
                <div className="row">
                    <div className="col">
                        <div className="subtitle">My Works</div>
                        <div className="title">Selected Projects</div>
                    </div>
                </div>
                <div className="row row-cols-1 row-cols-lg-2">
                    {projectList}
                </div>
            </div>
        </section>
    )
}

const mapStateToProps = state => {
    const { projects } = state
    return { projects }
}

export default connect(mapStateToProps)(Projects)