import React from 'react'
import Hero from './sections/Hero'
import About from './sections/About'
import Services from './sections/Services'
import Skills from './sections/Skills'
import Projects from './sections/Projects'
import Interest from './sections/Interest'
import Contact from './sections/Contact'
import { Helmet } from 'react-helmet'
import { withRouter } from 'react-router-dom'

const LandingPage = ({ history }) => {
    const stretchedLink = (e) => {
        const id = e.target.dataset.id
        if (id) {
            history.push(`/project/${id}`)
        }
    }

    return (
        <div>
            <Helmet>
                <title>Dicky Setiawan | Full Stack Developer</title>
                <meta name="description" content="Hello, my name is Dicky Setiawan. A Creative Freelancer & Full Stack Developer, based in Indonesia." />
            </Helmet>
            <Hero />
            <About />
            <Services />
            <Skills />
            <Projects stretchedLink={stretchedLink} />
            <Interest />
            <Contact />
        </div>
    )
}
export default withRouter(LandingPage)