import React from 'react'
import LazyLoad from 'react-lazyload'
import { Link } from 'react-router-dom'

const ProjectList = ({ projects, stretchedLink }) => {
    return projects.length ? (
        projects.map(project => (
            <div key={project.id} className="col project-wrapper">
                <div className="image-wrapper" onClick={stretchedLink} data-id={project.id}>
                    <LazyLoad throttle={750} placeholder={(<img className="project-image img-fluid" src="https://res.cloudinary.com/ds-projects/image/upload/dysetiawan/image.png" alt={project.title} />)}>
                        <img className="project-image img-fluid" src={project.image} alt={project.title} />
                    </LazyLoad>
                </div>
                <div className="link-wrapper">
                    <Link to={`/project/${project.id}`}>{project.title}</Link>
                </div>
            </div>
        ))
    ) : (<div className="col"></div>)
}

export default ProjectList