import React from 'react'

const Hero = () => {
    return (
        <section id="hero">
            <div className="container">
                <div className="row row-cols-1">
                    <div className="col title-wrapper">
                        <h1 className="title">Hello, <br />I am <span>Dicky</span>, <br />Full Stack Developer</h1>
                    </div>
                    <div className="col subtitle-wrapper">
                        <div className="subtitle left scrollspy-btn" data-target="#about">Scroll Down</div>
                    </div>
                </div>
            </div>
        </section>
    )
}
export default Hero